const days = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado'];
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
let result = '';
for (let i = 1; i <= 10; i++) {
  const future = new Date(now);
  future.setDate(now.getDate() + i);
  let label = '';
  if (i === 1) {
    label = `Amanhã é ${days[future.getDay()]} ${pad(future.getDate())}/${pad(future.getMonth() + 1)}/${future.getFullYear()}`;
  } else if (i === 2) {
    label = `Depois de amanhã é ${days[future.getDay()]} ${pad(future.getDate())}/${pad(future.getMonth() + 1)}/${future.getFullYear()}`;
  } else {
    label = `${days[future.getDay()]} será dia ${pad(future.getDate())}/${pad(future.getMonth() + 1)}/${future.getFullYear()}`;
  }
  result += `${label}\n`;
}
return [
  {
    json: {
      resultado: result.trim()
    }
  }
];

